import React, { createContext, useContext, useState, useCallback } from 'react';

const COLORS = { info: '#2563eb', success: '#16a34a', error: '#dc2626' };

const ToastContext = createContext(null);

export function useToasts() {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error('useToasts must be used inside <Toaster>');
  return ctx;
}

export default function Toaster({ children }) {
  const [toasts, setToasts] = useState([]);

  const remove = useCallback((id) => {
    setToasts((t) => t.filter((x) => x.id !== id));
  }, []);

  const add = useCallback(
    (message, type = 'info', duration = 3000) => {
      const id = Date.now() + Math.random();
      setToasts((t) => [...t, { id, message, type }]);
      setTimeout(() => remove(id), duration);
    },
    [remove]
  );

  return (
    <ToastContext.Provider value={{ add, remove }}>
      {children}
      <div style={{ position: 'fixed', top: 16, right: 16, display: 'flex', flexDirection: 'column', gap: 8, zIndex: 1000 }}>
        {toasts.map((t) => (
          <div
            key={t.id}
            role="status"
            style={{
              minWidth: 220,
              padding: '10px 14px',
              borderRadius: 8,
              color: '#fff',
              background: COLORS[t.type] || COLORS.info,
              boxShadow: '0 4px 14px rgba(0,0,0,0.2)',
              display: 'flex',
              justifyContent: 'space-between',
              gap: 12,
            }}
          >
            <span>{t.message}</span>
            <button
              onClick={() => remove(t.id)}
              aria-label="Dismiss"
              style={{ border: 'none', background: 'none', color: '#fff', cursor: 'pointer', fontSize: 16 }}
            >
              ✕
            </button>
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

