import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Toast { id: number; message: string; type: string; }

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Toast Demo</h1>
      <div style="display: flex; gap: 8px;">
        <button (click)="add('Saved successfully', 'success')" style="padding: 8px 14px; cursor: pointer;">Success</button>
        <button (click)="add('Something went wrong', 'error')" style="padding: 8px 14px; cursor: pointer;">Error</button>
        <button (click)="add('Heads up — new update', 'info')" style="padding: 8px 14px; cursor: pointer;">Info</button>
      </div>

      <div style="position: fixed; top: 16px; right: 16px; display: flex; flex-direction: column; gap: 8px; z-index: 1000;">
        <div
          *ngFor="let t of toasts; trackBy: trackById"
          role="status"
          [style.background]="colorFor(t.type)"
          style="min-width: 220px; padding: 10px 14px; border-radius: 8px; color: #fff; box-shadow: 0 4px 14px rgba(0,0,0,0.2); display: flex; justify-content: space-between; gap: 12px;"
        >
          <span>{{ t.message }}</span>
          <button (click)="remove(t.id)" aria-label="Dismiss" style="border: none; background: none; color: #fff; cursor: pointer; font-size: 16px;">✕</button>
        </div>
      </div>
    </div>
  `,
})
export class AppComponent {
  toasts: Toast[] = [];

  add(message: string, type: string = 'info', duration = 3000): void {
    const id = Date.now() + Math.random();
    this.toasts.push({ id, message, type });
    setTimeout(() => this.remove(id), duration);
  }

  remove(id: number): void {
    this.toasts = this.toasts.filter((t) => t.id !== id);
  }

  colorFor(type: string): string {
    const map: Record<string, string> = { info: '#2563eb', success: '#16a34a', error: '#dc2626' };
    return map[type] ? map[type] : map['info'];
  }

  trackById(_i: number, t: Toast): number {
    return t.id;
  }
}

@NgModule({
  declarations: [AppComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
